import subprocess

def executeCommand():
    command = input("Enter command: ").strip()
    if not command:
        print("Empty command")
        return
    if any(c in command for c in ';|&<>()'):
        print("Invalid command")
        return
    parts = command.split()
    if not parts:
        print("Empty command")
        return
    try:
        subprocess.run(parts, check=True)
    except subprocess.CalledProcessError as e:
        print(f"Command failed: {e}")

